const body = $json.original || $json.body || $json;
const text = `${body.title || body.titulo || ''} ${body.entidad || ''} ${body.tipo || ''} ${body.description || body.descripcion || ''} ${body.excerpt || body.extracto || ''}`.toLowerCase();
const chemicalRules = ['reactivo', 'quimico', 'quimico', 'laboratorio', 'desinfectante', 'hipoclorito', 'etanol', 'isopropanol', 'solvente', 'analisis clinico'];
const purchaseRules = ['subasta', 'infima', 'ínfima', 'proforma', 'contratacion', 'contratación'];
const hits = [...new Set(chemicalRules.filter((token) => text.includes(token)))];
const purchaseHits = [...new Set(purchaseRules.filter((token) => text.includes(token)))];
const tipo = String(body.tipo || 'Sin tipo');
let encaje = Math.min(100, hits.length * 16 + purchaseHits.length * 10 + (/subasta|infima|ínfima/i.test(tipo) ? 20 : 5));
let recomendacion = encaje >= 70 ? 'participar' : encaje >= 45 ? 'revisar' : 'no_participar';
const riesgos = [];
if (!body.url) riesgos.push('No se proporciono la URL oficial del proceso para validar el pliego.');
if (!body.excerpt && !body.extracto) riesgos.push('No se adjunto extracto documental para revisar requisitos tecnicos.');
if (!hits.length) riesgos.push('El match tecnico con quimica es debil y requiere validacion manual.');
const checklist = [
  'Validar ficha y pliego oficial en SERCOP.',
  'Confirmar fecha limite, forma de entrega y vigencia de oferta.',
  'Verificar especificaciones tecnicas y presentaciones requeridas.',
  'Confirmar stock, tiempos de importacion o abastecimiento y certificados.',
  'Preparar cotizacion y documentos habilitantes del proveedor.'
];
const lista = hits.length ? hits.map((hit) => `Cotizar linea relacionada con ${hit}.`) : ['Solicitar cotizacion base y confirmar si el requerimiento realmente pertenece a la linea quimica.'];
const preguntas = [];
if (!body.entidad) preguntas.push('Cual es la entidad contratante exacta?');
if (!body.url) preguntas.push('Cual es la URL oficial del proceso en SERCOP?');
if (!body.excerpt && !body.extracto) preguntas.push('Que requisitos documentales o tecnicos aparecen en el pliego?');
const estrategia = hits.length
  ? `Priorizar cotizacion rapida para ${hits.join(', ')} y confirmar equivalencias tecnicas antes de ofertar.`
  : 'Levantar mas informacion tecnica antes de decidir si se participa.';
return [{
  json: {
    ok: true,
    mode: 'rules_fallback',
    analysis: {
      resumen_ejecutivo: `Proceso ${recomendacion} con encaje estimado ${encaje}/100. Coincidencias detectadas: ${hits.join(', ') || 'sin coincidencias claras'}.`,
      recomendacion,
      encaje,
      riesgos,
      checklist_documental: checklist,
      estrategia_abastecimiento: estrategia,
      lista_cotizacion_sugerida: lista,
      preguntas_abiertas: preguntas
    }
  }
}];
